module adder_32bit(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

    wire [31:0] P, G;
    wire [32:1] C;

    // Generate and Propagate signals
    assign P = A ^ B;
    assign G = A & B;

    // Carry-Lookahead Tree
    wire [31:0] C1, C2, C4, C8, C16;

    // Level 1
    assign C[1] = G[0] | (P[0] & C[0]);
    assign C1[0] = G[1] | (P[1] & C[1]);
    assign C[2] = G[2] | (P[2] & C[2]);
    assign C2[1:0] = G[3:2] | (P[3:2] & C[3:2]);
    assign C[4] = G[4] | (P[4] & C[4]);
    assign C4[3:0] = G[7:4] | (P[7:4] & C[7:4]);
    assign C[8] = G[8] | (P[8] & C[8]);
    assign C8[7:0] = G[15:8] | (P[15:8] & C[15:8]);
    assign C[16] = G[16] | (P[16] & C[16]);
    assign C16[15:0] = G[31:16] | (P[31:16] & C[31:16]);

    // Level 2
    assign C[32] = G[31] | (P[31] & C[31]);
    assign C32 = C[32];

    // Sum Calculation
    assign S[1] = P[0] ^ C[0];
    assign S[31:2] = P[31:2] ^ C[31:2];

endmodule
